  stribog:   { c1: '#5878a0', c2: '#101830', label: 'Sovereign · Grandfather of the Winds',    glyph: '🌬' },
  lada:      { c1: '#c898b0', c2: '#481838', label: 'Life · Spring-Love-Goddess (contested)',  glyph: '🌸' },
  yarilo:    { c1: '#a8c038', c2: '#283808', label: 'Life · Dying-and-Rising Spring-Young-God', glyph: '🌾' },
